commit 6baf08242f2572002e57ff88f91cfc6b90516266
Author: Kevin Ansfield <kevin@lookingsideways.co.uk>
Date:   Tue Feb 3 19:02:16 2026 +0000

    Added `/comments/:id/reports/` Admin API endpoint

    ref https://linear.app/ghost/issue/BER-3196/

    In order to support displaying who reported a comment in the comment moderation screen we need an API endpoint to fetch the reports and the reporting members.

diff --git a/ghost/core/core/server/api/endpoints/comment-reports.js b/ghost/core/core/server/api/endpoints/comment-reports.js
new file mode 100644
index 0000000000..dd0844e2ec
--- /dev/null
+++ b/ghost/core/core/server/api/endpoints/comment-reports.js
@@ -0,0 +1,34 @@
+// Endpoint for the admin API to return reporters for a comment
+
+const commentsService = require('../../services/comments');
+
+/** @type {import('@tryghost/api-framework').Controller} */
+const controller = {
+    docName: 'comment_reports',
+    browse: {
+        headers: {
+            cacheInvalidate: false
+        },
+        options: [
+            'id',
+            'page',
+            'limit'
+        ],
+        validation: {
+            options: {
+                id: {
+                    required: true
+                }
+            }
+        },
+        // Use comment permissions - browsing reports is part of comment moderation
+        permissions: {
+            docName: 'comments'
+        },
+        query(frame) {
+            return commentsService.controller.getCommentReporters(frame);
+        }
+    }
+};
+
+module.exports = controller;

